sys_security_acl.script:
if (gs.hasRole('x_2097092_linq.platform_admin')) {
  answer = true;
} else if (gs.hasRole('x_2097092_linq.college_admin')) {
  // College admin reads registrations for events in their college
  var userCollege = gs.getUser().getRecord().getValue('u_college');
  var eventGr = new GlideRecord('x_2097092_linq_event');
  eventGr.get(current.getValue('event'));
  answer = (eventGr.getValue('college') == userCollege);
} else if (gs.hasRole('x_2097092_linq.club_admin') || gs.hasRole('x_2097092_linq.club_member')) {
  // Club admin/member reads registrations for their club events
  var eventGr2 = new GlideRecord('x_2097092_linq_event');
  eventGr2.get(current.getValue('event'));
  var clubId = eventGr2.getValue('club');
  var gr = new GlideRecord('x_2097092_linq_club_membership');
  gr.addQuery('member', gs.getUserID());
  gr.addQuery('club', clubId);
  gr.addQuery('status', 'active');
  gr.query();
  if (gr.hasNext()) {
    answer = true;
  } else {
    // Fall through to own-record check
    answer = (current.getValue('student') == gs.getUserID());
  }
} else {
  // Students: read only their own registrations
  answer = (current.getValue('student') == gs.getUserID());
}
